module shift_reg8 (
    input clk,
    input rst,
    input si,
    output [7:0] po
);

    reg [7:0] shift_register;

    always @(posedge clk or posedge rst) begin
        if (rst)
            shift_register <= 8'b00000000;
        else
            shift_register <= {shift_register[6:0], si};
    end

    assign po = shift_register;

endmodule
